const express = require('express');
const PatternController = require('../controllers/patternController');
const { authenticateToken, requireAdmin } = require('../middleware/auth');
const { validateRequest } = require('../middleware/validation');

const router = express.Router();

// 公开接口 - 无需认证
router.get('/manifest', PatternController.getManifest);
router.get('/:id', PatternController.getPattern);
router.get('/verified/list', PatternController.getVerifiedPatterns);

// 管理员接口 - 需要认证和权限
router.post('/', authenticateToken, requireAdmin, PatternController.createPattern);
router.put('/:id', authenticateToken, requireAdmin, PatternController.updatePattern);
router.patch('/:id/verify', authenticateToken, requireAdmin, PatternController.verifyPattern);
router.delete('/:id', authenticateToken, requireAdmin, PatternController.deletePattern);

module.exports = router;
